#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    long long dp[N + 1];
    dp[1] = 2;
    for (int i = 2; i <= N; i++) {
        dp[i] = (1LL << i) % M;
        for (int j = 1; j * j <= i; j++) {
            if (i % j == 0) {
                dp[i] = (dp[i] - dp[j] + M) % M;
                if (j * j != i) {
                    dp[i] = (dp[i] - dp[i / j] + M) % M;
                }
            }
        }
    }
    printf("%lld\n", dp[N]);
    return 0;
}

